class Trie {
public:
    Trie() {
        root = new Node();
    }

    void insert(string word) {
        Node* node = root;
        for (char c : word) {
            if (!node->children[c - 'a']) {
                node->children[c - 'a'] = new Node();
            }
            node = node->children[c - 'a'];
        }
        node->isEndOfWord = true;
    }

    bool search(string word) {
        Node* node = root;
        for (char c : word) {
            if (!node->children[c - 'a']) {
                return false;
            }
            node = node->children[c - 'a'];
        }
        return node->isEndOfWord;
    }

    bool startsWith(string prefix) {
        Node* node = root;
        for (char c : prefix) {
            if (!node->children[c - 'a']) {
                return false;
            }
            node = node->children[c - 'a'];
        }
        return true;
    }

private:
    struct Node {
        bool isEndOfWord;
        Node* children[26];
    };
    Node* root;
};
```

